"""Circle packing n=26: COBYLA derivative-free optimization with multiple initializations"""
import numpy as np
from scipy.optimize import minimize

def construct_packing():
    """
    Optimize 78 variables (26 centers + 26 radii) using COBYLA derivative-free method.
    COBYLA builds linear approximations using function values only, which can better
    navigate complex nonlinear overlap constraints without gradient information.
    Multiple initialization strategies for robustness.
    """
    n = 26

    def objective(vars):
        return -np.sum(vars[2::3])

    def constraints(vars):
        cons = []
        for i in range(n):
            x, y, r = vars[3*i], vars[3*i+1], vars[3*i+2]
            cons.extend([x - r, 1 - x - r, y - r, 1 - y - r])
        for i in range(n):
            for j in range(i + 1, n):
                dx = vars[3*i] - vars[3*j]
                dy = vars[3*i+1] - vars[3*j+1]
                ri, rj = vars[3*i+2], vars[3*j+2]
                cons.append(dx*dx + dy*dy - (ri + rj)**2)
        return np.array(cons)

    init_patterns = [
        [5, 4, 5, 4, 5, 3],
        [4, 5, 4, 5, 4, 4],
        [3, 5, 4, 5, 4, 5],
        [4, 4, 5, 5, 4, 4],
        [5, 5, 4, 4, 4, 4],
    ]

    best_sum, best_result = 0, None

    for seed in range(30):
        np.random.seed(seed)
        x0 = np.zeros(3 * n)
        pattern = init_patterns[seed % len(init_patterns)]

        y_step = 1.0 / (len(pattern) + 1)
        idx = 0
        for row_idx, count in enumerate(pattern):
            y = y_step * (row_idx + 1)
            x_step = 1.0 / (count + 1)
            for i in range(count):
                x = x_step * (i + 1)
                if row_idx % 2 == 1:
                    x += x_step * 0.5
                x0[3*idx] = np.clip(x + np.random.uniform(-0.03, 0.03), 0.05, 0.95)
                x0[3*idx+1] = np.clip(y + np.random.uniform(-0.03, 0.03), 0.05, 0.95)
                x0[3*idx+2] = 0.05 + np.random.uniform(0, 0.02)
                idx += 1

        try:
            result = minimize(objective, x0, method='COBYLA',
                            constraints={'type': 'ineq', 'fun': constraints},
                            options={'rhobeg': 0.08, 'maxiter': 2500, 'tol': 1e-8})

            radii = result.x[2::3]
            centers = result.x.reshape(n, 3)[:, :2]

            valid = True
            for i in range(n):
                if radii[i] <= 0 or centers[i,0] - radii[i] < 0 or centers[i,0] + radii[i] > 1:
                    valid = False
                    break
                if centers[i,1] - radii[i] < 0 or centers[i,1] + radii[i] > 1:
                    valid = False
                    break

            if valid:
                for i in range(n):
                    for j in range(i+1, n):
                        dist = np.linalg.norm(centers[i] - centers[j])
                        if radii[i] + radii[j] > dist + 1e-8:
                            valid = False
                            break
                    if not valid:
                        break

            if valid:
                sum_radii = np.sum(radii)
                if sum_radii > best_sum:
                    best_sum = sum_radii
                    best_result = result.x.copy()
        except:
            continue

    if best_result is None:
        best_result = x0

    centers = best_result.reshape(n, 3)[:, :2]
    radii = np.maximum(best_result[2::3], 1e-8)

    return centers, radii, np.sum(radii)
